code_changes.content:
[
  {
    "file": "lib/base64.c",
    "line": 203,
    "severity": "critical",
    "description": "Integer overflow in base64_encode() allows heap buffer overflow. The removed check prevents integer overflow when calculating malloc size on 32-bit systems. If insize is close to SIZE_MAX, the expression (insize + 2) / 3 * 4 + 1 wraps around causing a tiny allocation followed by massive buffer overflow during encoding.",
    "fix_patch": "--- a/lib/base64.c
+++ b/lib/base64.c
@@ -200,6 +200,11 @@ static CURLcode base64_encode(const char *table64,
   if(!insize)
     insize = strlen(inputbuff);

+#if SIZEOF_SIZE_T == 4
+  if(insize > UINT_MAX/4)
+    return CURLE_OUT_OF_MEMORY;
+#endif
+
   base64data = output = malloc((insize + 2) / 3 * 4 + 1);
   if(!output)
     return CURLE_OUT_OF_MEMORY;"
  },
  {
    "file": "lib/cookie.c",
    "line": 154,
    "severity": "high",
    "description": "Off-by-one error in cookie_tailmatch() violates RFC 6265 domain scoping. The missing -1 in pointer arithmetic causes the function to check the wrong character position when validating that a hostname belongs to a cookie domain. This allows cookies to be sent to hosts that should not receive them per RFC 6265 specifications.",
    "fix_patch": "--- a/lib/cookie.c
+++ b/lib/cookie.c
@@ -151,7 +151,7 @@ static bool cookie_tailmatch(const char *cookie_domain,
    */
   if(hostname_len == cookie_domain_len)
     return TRUE;
-  if('.' == *(hostname + hostname_len - cookie_domain_len))
+  if('.' == *(hostname + hostname_len - cookie_domain_len - 1))
     return TRUE;
   return FALSE;
 }"
  },
  {
    "file": "lib/transfer.c",
    "line": 166,
    "severity": "critical",
    "description": "Missing NULL pointer checks in xfer_recv_shutdown() causes null dereference crash. When called with NULL data or conn pointer, the function crashes at line 168 when dereferencing data->conn without validation. This violates secure coding practices and can cause denial of service.",
    "fix_patch": "--- a/lib/transfer.c
+++ b/lib/transfer.c
@@ -163,6 +163,8 @@ static CURLcode xfer_recv_shutdown(struct Curl_easy *data, bool *done)
 {
   int sockindex;

+  if(!data || !data->conn)
+    return CURLE_FAILED_INIT;
   if(data->conn->sockfd == CURL_SOCKET_BAD)
     return CURLE_FAILED_INIT;
   sockindex = (data->conn->sockfd == data->conn->sock[SECONDARYSOCKET]);"
  },
  {
    "file": "lib/vtls/openssl.c",
    "line": 992,
    "severity": "critical",
    "description": "Buffer overflow in passwd_callback() from removed size validation. The removed check num > klen before memcpy causes a heap buffer overflow when the password (klen bytes) exceeds the buffer size (num bytes). Additionally, removal of num >= 0 check allows negative buffer sizes. OpenSSL uses this callback for private key passwords, making this exploitable during certificate operations.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -989,10 +989,12 @@ static int passwd_callback(char *buf, int num, int encrypting,
 {
   DEBUGASSERT(0 == encrypting);

-  if(!encrypting) {
+  if(!encrypting && num >= 0) {
     int klen = curlx_uztosi(strlen((char *)global_passwd));
-    memcpy(buf, global_passwd, klen + 1);
-    return klen;
+    if(num > klen) {
+      memcpy(buf, global_passwd, klen + 1);
+      return klen;
+    }
   }
   return 0;
 }"
  },
  {
    "file": "lib/vtls/openssl.c",
    "line": 2364,
    "severity": "critical",
    "description": "Certificate verification bypass via embedded null bytes in SAN. Removed check (altlen == strlen(altptr)) allows Subject Alternative Names containing embedded null bytes to pass verification. An attacker can create a certificate with SAN like 'attacker.com\0legitimate.com' which would be accepted as valid for legitimate.com, completely bypassing certificate hostname verification.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -2361,7 +2361,10 @@ static CURLcode ossl_verifyhost(struct Curl_easy *data,
              It has been however verified that in 0.9.6 and 0.9.7, IA5String
              is always null-terminated.
           */
-          if(subj_alt_hostcheck(data, altptr, altlen,
+          if((altlen == strlen(altptr)) &&
+             /* if this is not true, there was an embedded zero in the name
+                string and we cannot match it. */
+             subj_alt_hostcheck(data, altptr, altlen,
                                 peer->hostname, hostlen,
                                 peer->dispname)) {
             dnsmatched = TRUE;"
  }
]

